  ('heelevel3-29a002de-moex-00015', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '依照實務見解，基於行使之目的而偽造貨幣，之後進而行使該偽幣，所成立之偽造貨幣罪（刑法 第195條第1項）與行使偽造貨幣罪（刑法第196條第1項）應如何論處？', '["偽造吸收行使，僅需論以偽造貨幣罪", "依想像競合之例從一重處斷", "依數罪併罰之例處斷", "成立補充關係，僅需論以行使偽造貨幣罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
